#!/usr/bin/env node
/**
 * scripts/build-data-bundle.js
 *
 * Reads data/*.json files and writes them as a TypeScript module that gets
 * compiled into the Next.js bundle. This is the "hacky fix" to make the
 * dashboard work on Vercel's read-only filesystem.
 *
 * Phase 1 only — Phase 2 replaces this with Supabase.
 *
 * Run: node scripts/build-data-bundle.js
 * Or add as `prebuild` in package.json so it runs before every build.
 */

const fs = require('fs');
const path = require('path');

const PROJECT_ROOT = path.resolve(__dirname, '..');
const DATA_DIR = path.join(PROJECT_ROOT, 'data');
const OUT_FILE = path.join(PROJECT_ROOT, 'lib', 'data-bundle', 'bundle.ts');

function readJson(file, fallback) {
  const p = path.join(DATA_DIR, file);
  if (!fs.existsSync(p)) {
    console.warn(`  ! ${file} not found, using fallback`);
    return fallback;
  }
  try {
    return JSON.parse(fs.readFileSync(p, 'utf8'));
  } catch (e) {
    console.error(`  ! Failed to parse ${file}: ${e.message}`);
    return fallback;
  }
}

function jsonToTs(obj) {
  // Emit the data as `JSON.parse("…")` rather than an inline object/array
  // literal. With a large, heterogeneous array (2k+ leads), the inline
  // literal makes TypeScript compute a union of every element's shape and
  // fail during `next build` type-check with TS2590 "Expression produces a
  // union type that is too complex to represent" — even with a `: any[]`
  // annotation on the binding. `JSON.parse` is typed `any`, so no literal-
  // element union is ever computed. The data is still bundled (as a string
  // constant) and parsed once at module load.
  return `JSON.parse(${JSON.stringify(JSON.stringify(obj))})`;
}

console.log('Building data bundle...');

const leads = readJson('leads.json', []);
const prototypes = readJson('prototypes.json', []);
const outreachLog = readJson('outreach_logs.json', { logs: [] });
const conversionStats = readJson('conversion-stats.json', {});
const agentmailInboxes = readJson('agentmail_inboxes.json', { inboxes: [] });

const generatedAt = new Date().toISOString();

const content = `// AUTO-GENERATED by scripts/build-data-bundle.js — do not edit by hand.
// Phase 1 "hacky fix" — replaced by Supabase in Phase 2.

export const BUNDLE_GENERATED_AT = ${JSON.stringify(generatedAt)};

export const leads: any[] = ${jsonToTs(leads)};

export const prototypes: any[] = ${jsonToTs(prototypes)};

export const outreachLog: any = ${jsonToTs(outreachLog)};

export const conversionStats: any = ${jsonToTs(conversionStats)};

export const agentmailInboxes: any = ${jsonToTs(agentmailInboxes)};
`;

fs.mkdirSync(path.dirname(OUT_FILE), { recursive: true });
fs.writeFileSync(OUT_FILE, content, 'utf8');

console.log(`  ✓ leads: ${leads.length}`);
console.log(`  ✓ prototypes: ${prototypes.length}`);
console.log(`  ✓ outreach log entries: ${outreachLog.logs?.length || 0}`);
console.log(`  → ${path.relative(PROJECT_ROOT, OUT_FILE)}`);
console.log(`  → generated at ${generatedAt}`);